      {
        "text": "Bundling technology migration with service extraction approximately doubles delivery time",
        "truth": 0.88,
        "indeterminacy": 0.1,
        "falsity": 0.02
      },
      {
        "text": "Inventory DynamoDB migration estimate of 3 weeks is false; realistic is 8-12 weeks for extraction + storage migration",
        "truth": 0.85,
        "indeterminacy": 0.12,
        "falsity": 0.03
      },
      {
        "text": "Isolation of change variables is more valuable than architectural perfection in extraction phase",
        "truth": 0.91,
        "indeterminacy": 0.07,
        "falsity": 0.02
      }
    ],
    "depends_on": ["Migration Critical Path and Timeline"]
