        "text": "Architecture decision velocity determines migration duration more than engineering velocity",
        "truth": 0.83,
        "indeterminacy": 0.14,
        "falsity": 0.03
      },
      {
        "text": "Empowered single decision maker on architectural calls enables faster migration than consensus-driven committee",
        "truth": 0.8,
        "indeterminacy": 0.16,
        "falsity": 0.04
      }
    ],
    "depends_on": ["Scope Creep Prevention and Extraction Discipline"]
  }
